          '6': { text: 'Me gusta organizar datos, documentos o registros de manera ordenada y sistem\u00e1tica.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '7': { text: 'Prefiero trabajar con m\u00e1quinas, herramientas o equipos en lugar de trabajar con personas.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '8': { text: 'Disfruto analizando datos y resolviendo problemas complejos y abstractos.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '9': { text: 'Valoro la libertad para improvisar y pensar fuera de lo convencional.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '10': { text: 'Disfruto ense\u00f1ando, entrenando o tutelando a otros.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '11': { text: 'Me motiva iniciar negocios o liderar proyectos hacia metas ambiciosas.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '12': { text: 'Prefiero seguir procedimientos establecidos en lugar de crear mis propias reglas.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
          '13': { text: 'Disfruto de las actividades f\u00edsicas o del trabajo al aire libre.', options: ['Nada como yo', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
