          '2': { text: 'Veo f\u00e1cilmente lo que necesita mejorarse y siento un fuerte impulso de corregirlo.', options: ['No se parece a m\u00ed', 'Un poco como yo', 'Bastante como yo', 'Muy como yo'] },
