          '12': { text: '\u00bfDe qu\u00e9 color es un cielo despejado?', options: ['Verde', 'Azul', 'Rojo', 'Amarillo'] },
          '13': { text: '4 \u00d7 3 = ?', options: ['7', '12', '14', '16'] },
          '14': { text: '\u00bfCu\u00e1l NO es un instrumento musical?', options: ['Viol\u00edn', 'Piano', 'Guitarra', 'Libro'] },
