          '8': { text: 'Si ROJO = 27, entonces GATO = ?', options: ['24', '27', '30', '33'] },
          '9': { text: '\u00bfCu\u00e1l es el \u00e1rea de un rect\u00e1ngulo de 8 cm \u00d7 5 cm?', options: ['30 cm\u00b2', '35 cm\u00b2', '40 cm\u00b2', '45 cm\u00b2'] },
