          '14': { text: '\u00bfQu\u00e9 tienen en com\u00fan una novela y una biograf\u00eda?', options: ['Ambas son ficci\u00f3n', 'Ambas son formas de libro', 'Ambas son no ficci\u00f3n', 'Ambas son poes\u00eda'] },
          '15': { text: '\u00bfQu\u00e9 figura tiene 3 lados?', options: ['Cuadrado', 'Pent\u00e1gono', 'Tri\u00e1ngulo', 'Hex\u00e1gono'] },
